import{_ as e,o,c as r,ag as a}from"./chunks/framework.CbQjVMS6.js";const h=JSON.parse('{"title":"Powerpack Outputs","description":"","frontmatter":{},"headers":[],"relativePath":"outputs.md","filePath":"outputs.md","lastUpdated":1774323326000}'),i={name:"outputs.md"};function s(d,t,p,n,u,c){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="powerpack-outputs" tabindex="-1">Powerpack Outputs <a class="header-anchor" href="#powerpack-outputs" aria-label="Permalink to &quot;Powerpack Outputs&quot;">​</a></h1><p>Every time you run <code>Powerpack.exe</code> to process/optimize your 8XP program, it will read the program source code and generate several files.</p><p>Here’s an explanation of each and what you might use them for:</p><table tabindex="0"><thead><tr><th>Subfolder</th><th>File</th><th>Description</th></tr></thead><tbody><tr><td>Compiled Programs</td><td>YOURPROG.optimized.8xp</td><td>The compiled and <a href="/features/ti-basic-optimization">optimized</a> version of your program. This is the file you want to load onto your calculator and/or run in WabbitEmu.</td></tr><tr><td> </td><td>YOURPROG.optimized.theta.8xp</td><td>A <a href="/features/theta-backup">backup copy</a> of the compiled and optimized program. Using this is completely optional.</td></tr><tr><td>Source Code as Text</td><td>YOURPROG.8xp-source</td><td>A copy of the <a href="/features/decompile-8xp">original source code in plain text</a> (if the original file is an 8XP binary file). Useful for keeping track of changes in git / version control.</td></tr><tr><td> </td><td>YOURPROG.optimized.8xp-source</td><td>A <a href="/features/decompile-8xp">plain text version of the “optimized” code</a>, after Powerpack has processed it, where all comments and extraneous characters have been removed. Useful for git / version control.</td></tr><tr><td> </td><td>YOURPROG.optimized.8xp-byte-counts</td><td>A <a href="/features/file-size-reports">file size report</a> showing the number of bytes used on each line. Useful for keeping track of file size with git / version control.</td></tr></tbody></table><p>Future versions of Powerpack will allow you to specify whether or not to output these files, and to which locations. For now, they are all output in the above structure.</p>',5)])])}const f=e(i,[["render",s]]);export{h as __pageData,f as default};
